  @impl true
  def handle_call({:validate_transaction, transaction}, _from, state) do
    # Get the current balance for the account associated with the transaction
    current_balance = :ets.lookup(@ets_table_name, transaction.account)

    # Check if the transaction is valid based on the current balance and the amount being transferred
    case transaction.amount <= current_balance do
      true ->
